                const agentMsg = {
                    id: `msg_${Date.now()}_agent`,
                    agent_name: targetAgent.name,
                    message: data.message,
                    timestamp: Date.now(),
                    read_by: []
                };
                const afterConfig = {
                    ...updatedConfig,
                    chat: {
                        messages: [
                            ...updatedConfig.chat.messages,
                            agentMsg
                        ]
                    }
                };
